#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // 1. Create a buffer_adaptor for the provided buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // 2. Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // 3. Check available space using buffer_adaptor's size() method
    // 4. Calculate total data size needed (header + items)
    const auto required_size = sizeof(header) + (items.size() * sizeof(uint32_t));

    // 5. If space is sufficient, get the write pointer using buffer_adaptor's write_ptr()
    if (adaptor.size() >= required_size) {
        // Get write pointer
        auto* write_ptr = adaptor.write_ptr();

        // Write header
        std::memcpy(write_ptr, &header, sizeof(header));
        write_ptr += sizeof(header);

        // 6. Use write_container for the items vector
        // Calculate how many items can fit in remaining space
        const auto remaining_space = adaptor.size() - sizeof(header);
        const auto items_to_write = remaining_space / sizeof(uint32_t);

        // Write only what fits
        if (items_to_write > 0) {
            // Create a temporary vector with only the items that fit
            std::vector<uint32_t> temp_items(items.begin(), 
                                            items.begin() + items_to_write);

            // Use binary_stream's write_container method
            stream.write_container(temp_items);
        }

        return true;
    }

    return false;
}
